<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0"/>
<title>WastedToken Mint</title>
<style>
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  html,body{height:100%;background:#0a0a0f;color:#e8e6df;font-family:'Segoe UI',system-ui,-apple-system,sans-serif;overflow-x:hidden}

  /* ── Hero ─────────────────────────────────────── */
  .hero{position:relative;width:100%;height:72vh;display:flex;align-items:center;justify-content:center;background:radial-gradient(ellipse at center,#141428 0%,#0a0a0f 65%)}
  #coin-hero{width:100%;height:100%;display:block}

  /* ── About ─────────────────────────────────────── */
  .about{max-width:720px;margin:0 auto;padding:80px 24px;text-align:center;position:relative;z-index:2}
  .about h2{font-size:clamp(1.6rem,3vw,2.4rem);letter-spacing:.04em;color:#c9b896;margin-bottom:16px}
  .about p{color:#a8a397;line-height:1.85;font-size:clamp(.95rem,2vw,1.1rem);max-width:600px;margin-inline:auto}

  /* ── Collection ─────────────────────────────────── */
  .collection{padding:40px 24px 80px;max-width:1100px;margin:0 auto}
  .collection h3{font-size:clamp(1.3rem,2.5vw,1.9rem);text-align:center;color:#c9b896;margin-bottom:32px;letter-spacing:.06em;text-transform:uppercase;font-weight:700}
  .grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:24px}

  /* ── Edition tile ──────────────────────────────── */
  .edition{background:#13131f;border-radius:16px;padding:28px;text-align:center;position:relative;overflow:hidden;border:1px solid #1e1e2a;transition:border-color .3s,transform .3s}
  .edition:hover{border-color:#4a3f2a;transform:translateY(-2px)}
  .edition h4{font-size:.95rem;color:#c9b896;margin-bottom:10px;text-transform:uppercase;letter-spacing:.1em;font-weight:700}
  .edition canvas.edition-canvas{width:100%;height:auto;display:block;border-radius:8px;background:#0d0d14}
  .edition .status{font-size:.75rem;color:#6b635a;margin-top:10px;letter-spacing:.06em;text-transform:uppercase;font-weight:600}
  .edition button.buy{margin-top:12px;padding:8px 24px;border:none;border-radius:8px;background:linear-gradient(135deg,#c9b896,#a8977a);color:#0a0a0f;font-weight:700;cursor:pointer;font-size:.85rem;letter-spacing:.04em;width:100%;transition:opacity .2s}
  button.buy:hover{opacity:.85}
  .edition[data-state="sold-out"] button.buy,.edition[data-state="coming-soon"] button.buy{background:#3a3a4a;color:#6b635a;cursor:not-allowed;pointer-events:none;opacity:.5}

  /* ── Footer ─────────────────────────────────────── */
  footer{text-align:center;padding:28px;font-size:.78rem;color:#4a443c;letter-spacing:.06em;text-transform:uppercase}
